import React, { useState, useEffect } from "react";
import "./Placement.css";

export default function Placement() {
  const user = JSON.parse(localStorage.getItem("loggedInUser")) || {};
  const [placements, setPlacements] = useState([]);
  const [newPlacement, setNewPlacement] = useState({
    role: "",
    company: "",
    eligibility: "",
  });

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("placements")) || [];
    setPlacements(stored);
  }, []);

  const handleAdd = () => {
    const updated = [...placements, newPlacement];
    localStorage.setItem("placements", JSON.stringify(updated));
    setPlacements(updated);
    setNewPlacement({ role: "", company: "", eligibility: "" });
  };

  const handleDelete = (index) => {
    const updated = placements.filter((_, i) => i !== index);
    localStorage.setItem("placements", JSON.stringify(updated));
    setPlacements(updated);
  };

  const handleApply = (index) => {
    alert(`Applied for ${placements[index].role} at ${placements[index].company}`);
  };

  const isAdminOrHR = user.role === "Admin" || user.role === "HR";

  return (
    <div className="placement-container">
      <h1>Placement Openings</h1>

      {isAdminOrHR && (
        <div className="form-section">
          <input
            type="text"
            placeholder="Role"
            value={newPlacement.role}
            onChange={(e) => setNewPlacement({ ...newPlacement, role: e.target.value })}
          />
          <input
            type="text"
            placeholder="Company"
            value={newPlacement.company}
            onChange={(e) => setNewPlacement({ ...newPlacement, company: e.target.value })}
          />
          <input
            type="text"
            placeholder="Eligibility"
            value={newPlacement.eligibility}
            onChange={(e) => setNewPlacement({ ...newPlacement, eligibility: e.target.value })}
          />
          <button onClick={handleAdd}>Add Placement</button>
        </div>
      )}

      <div className="card-grid">
        {placements.map((item, index) => (
          <div key={index} className="placement-card">
            <h3>{item.role}</h3>
            <h4>{item.company}</h4>
            <p>{item.eligibility}</p>

            {user.role === "Student" && (
              <button className="apply-btn" onClick={() => handleApply(index)}>
                Apply
              </button>
            )}

            {isAdminOrHR && (
              <button className="delete-btn" onClick={() => handleDelete(index)}>
                Delete
              </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
